## 场景

在一个日志采集服务中，你需要在每条日志前面拼接时间戳、主机名和日志级别，最终生成一条完整的字符串写入文件。系统每秒产生约五万条日志，因此字符串拼接的性能直接关系到 CPU 占用率和 GC 压力。同事在 Code Review 时提出，应该把现有的 `fmt.Sprintf` 替换成 `strings.Builder`，理由是 Builder 更快。你决定写一个 benchmark 来验证这个说法，同时也把 `+` 运算符和 `bytes.Buffer` 一并纳入测试。

```go
package bench

import (
	"bytes"
	"fmt"
	"strings"
	"testing"
)

const (
	timestamp = "2024-06-15T10:30:00Z"
	hostname  = "prod-log-collector-07"
	level     = "INFO"
	message   = "request completed successfully"
)

func BenchmarkPlusConcat(b *testing.B) {
	for i := 0; i < b.N; i++ {
		_ = "[" + timestamp + "] " + hostname + " " + level + ": " + message
	}
}

func BenchmarkSprintf(b *testing.B) {
	for i := 0; i < b.N; i++ {
		_ = fmt.Sprintf("[%s] %s %s: %s", timestamp, hostname, level, message)
	}
}

func BenchmarkBuilder(b *testing.B) {
	for i := 0; i < b.N; i++ {
		var sb strings.Builder
		sb.Grow(128)
		sb.WriteString("[")
		sb.WriteString(timestamp)
		sb.WriteString("] ")
		sb.WriteString(hostname)
		sb.WriteString(" ")
		sb.WriteString(level)
		sb.WriteString(": ")
		sb.WriteString(message)
		_ = sb.String()
	}
}

func BenchmarkBuffer(b *testing.B) {
	for i := 0; i < b.N; i++ {
		var buf bytes.Buffer
		buf.Grow(128)
		buf.WriteString("[")
		buf.WriteString(timestamp)
		buf.WriteString("] ")
		buf.WriteString(hostname)
		buf.WriteString(" ")
		buf.WriteString(level)
		buf.WriteString(": ")
		buf.WriteString(message)
		_ = buf.String()
	}
}

func BenchmarkJoin(b *testing.B) {
	parts := []string{"[" + timestamp + "]", hostname, level + ":", message}
	for i := 0; i < b.N; i++ {
		_ = strings.Join(parts, " ")
	}
}
```

### 思考

在 Go 1.22、AMD Ryzen 7 5800X 环境下运行 `go test -bench=. -benchmem`，你预期哪种方式最快？哪种方式内存分配次数最少？如果将场景从拼接 4 个短字符串改为在循环中拼接一万次，结果又会发生怎样的变化？试着在脑中构建一个从「少量拼接」到「大量拼接」的性能模型，然后再看下面的分析。
